9184 static bool isLoadCombineCandidateImpl(Value *Root, unsigned NumElts,
9185                                        TargetTransformInfo *TTI,
9186                                        bool MustMatchOrInst) {
9187   // Look past the root to find a source value. Arbitrarily follow the
9188   // path through operand 0 of any 'or'. Also, peek through optional
9189   // shift-left-by-multiple-of-8-bits.
9190   Value *ZextLoad = Root;
9191   const APInt *ShAmtC;
9192   bool FoundOr = false;
9193   while (!isa<ConstantExpr>(ZextLoad) &&
9194          (match(ZextLoad, m_Or(m_Value(), m_Value())) ||
9195           (match(ZextLoad, m_Shl(m_Value(), m_APInt(ShAmtC))) &&
9196            ShAmtC->urem(8) == 0))) {
9197     auto *BinOp = cast<BinaryOperator>(ZextLoad);
9198     ZextLoad = BinOp->getOperand(0);
9199     if (BinOp->getOpcode() == Instruction::Or)
9200       FoundOr = true;
9201   }
9202   // Check if the input is an extended load of the required or/shift expression.
9203   Value *Load;
9204   if ((MustMatchOrInst && !FoundOr) || ZextLoad == Root ||
9205       !match(ZextLoad, m_ZExt(m_Value(Load))) || !isa<LoadInst>(Load))
9206     return false;
9207 
9208   // Require that the total load bit width is a legal integer type.
9209   // For example, <8 x i8> --> i64 is a legal integer on a 64-bit target.
9210   // But <16 x i8> --> i128 is not, so the backend probably can't reduce it.
9211   Type *SrcTy = Load->getType();
9212   unsigned LoadBitWidth = SrcTy->getIntegerBitWidth() * NumElts;
9213   if (!TTI->isTypeLegal(IntegerType::get(Root->getContext(), LoadBitWidth)))
9214     return false;
9215 
9216   // Everything matched - assume that we can fold the whole sequence using
9217   // load combining.
9218   LLVM_DEBUG(dbgs() << "SLP: Assume load combining for tree starting at "
9219              << *(cast<Instruction>(Root)) << "\n");
9220 
9221   return true;
9222 }
