9066         Type *SrcSclTy = E->getMainOp()->getOperand(0)->getType();
9067         auto *SrcTy = FixedVectorType::get(SrcSclTy, VL.size());
9068         if (SrcSclTy->isIntegerTy() && ScalarTy->isIntegerTy()) {
9069           auto SrcIt = MinBWs.find(getOperandEntry(E, 0));
9070           unsigned BWSz = DL->getTypeSizeInBits(ScalarTy);
9071           unsigned SrcBWSz =
9072               DL->getTypeSizeInBits(E->getMainOp()->getOperand(0)->getType());
9073           if (SrcIt != MinBWs.end()) {
9074             SrcBWSz = SrcIt->second.first;
9075             SrcSclTy = IntegerType::get(SrcSclTy->getContext(), SrcBWSz);
9076             SrcTy = FixedVectorType::get(SrcSclTy, VL.size());
9077           }
9078           if (BWSz <= SrcBWSz) {
9079             if (BWSz < SrcBWSz)
9080               VecCost =
9081                   TTIRef.getCastInstrCost(Instruction::Trunc, VecTy, SrcTy,
9082                                           TTI::CastContextHint::None, CostKind);
9083             LLVM_DEBUG({
9084               dbgs()
9085                   << "SLP: alternate extension, which should be truncated.\n";
9086               E->dump();
9087             });
9088             return VecCost;
9089           }
9090         }
9091         VecCost = TTIRef.getCastInstrCost(E->getOpcode(), VecTy, SrcTy,
9092                                           TTI::CastContextHint::None, CostKind);
9093         VecCost +=
9094             TTIRef.getCastInstrCost(E->getAltOpcode(), VecTy, SrcTy,
9095                                     TTI::CastContextHint::None, CostKind);
9096       }
9097       SmallVector<int> Mask;
9098       E->buildAltOpShuffleMask(
9099           [E](Instruction *I) {
9100             assert(E->isOpcodeOrAlt(I) && "Unexpected main/alternate opcode");
9101             return I->getOpcode() == E->getAltOpcode();
9102           },
9103           Mask);
9104       VecCost += ::getShuffleCost(TTIRef, TargetTransformInfo::SK_PermuteTwoSrc,
9105                                   FinalVecTy, Mask);
9106       // Patterns like [fadd,fsub] can be combined into a single instruction
9107       // in x86. Reordering them into [fsub,fadd] blocks this pattern. So we
9108       // need to take into account their order when looking for the most used
9109       // order.
9110       unsigned Opcode0 = E->getOpcode();
9111       unsigned Opcode1 = E->getAltOpcode();
9112       // The opcode mask selects between the two opcodes.
9113       SmallBitVector OpcodeMask(E->Scalars.size(), false);
9114       for (unsigned Lane : seq<unsigned>(0, E->Scalars.size()))
9115         if (cast<Instruction>(E->Scalars[Lane])->getOpcode() == Opcode1)
9116           OpcodeMask.set(Lane);
9117       // If this pattern is supported by the target then we consider the
9118       // order.
9119       if (TTIRef.isLegalAltInstr(VecTy, Opcode0, Opcode1, OpcodeMask)) {
9120         InstructionCost AltVecCost = TTIRef.getAltInstrCost(
9121             VecTy, Opcode0, Opcode1, OpcodeMask, CostKind);
9122         return AltVecCost < VecCost ? AltVecCost : VecCost;
9123       }
9124       // TODO: Check the reverse order too.
9125       return VecCost;
9126     };
9127     return GetCostDiff(GetScalarCost, GetVectorCost);
9128   }
9129   default:
9130     llvm_unreachable("Unknown instruction");
9131   }
9132 }
