9134 bool BoUpSLP::isFullyVectorizableTinyTree(bool ForReduction) const {
9135   LLVM_DEBUG(dbgs() << "SLP: Check whether the tree with height "
9136                     << VectorizableTree.size() << " is fully vectorizable .\n");
9137 
9138   auto &&AreVectorizableGathers = [this](const TreeEntry *TE, unsigned Limit) {
9139     SmallVector<int> Mask;
9140     return TE->State == TreeEntry::NeedToGather &&
9141            !any_of(TE->Scalars,
9142                    [this](Value *V) { return EphValues.contains(V); }) &&
9143            (allConstant(TE->Scalars) || isSplat(TE->Scalars) ||
9144             TE->Scalars.size() < Limit ||
9145             ((TE->getOpcode() == Instruction::ExtractElement ||
9146               all_of(TE->Scalars, IsaPred<ExtractElementInst, UndefValue>)) &&
9147              isFixedVectorShuffle(TE->Scalars, Mask)) ||
9148             (TE->State == TreeEntry::NeedToGather &&
9149              TE->getOpcode() == Instruction::Load && !TE->isAltShuffle()));
9150   };
9151 
9152   // We only handle trees of heights 1 and 2.
9153   if (VectorizableTree.size() == 1 &&
9154       (VectorizableTree[0]->State == TreeEntry::Vectorize ||
9155        (ForReduction &&
9156         AreVectorizableGathers(VectorizableTree[0].get(),
9157                                VectorizableTree[0]->Scalars.size()) &&
9158         VectorizableTree[0]->getVectorFactor() > 2)))
9159     return true;
9160 
9161   if (VectorizableTree.size() != 2)
9162     return false;
9163 
9164   // Handle splat and all-constants stores. Also try to vectorize tiny trees
9165   // with the second gather nodes if they have less scalar operands rather than
9166   // the initial tree element (may be profitable to shuffle the second gather)
9167   // or they are extractelements, which form shuffle.
9168   SmallVector<int> Mask;
9169   if (VectorizableTree[0]->State == TreeEntry::Vectorize &&
9170       AreVectorizableGathers(VectorizableTree[1].get(),
9171                              VectorizableTree[0]->Scalars.size()))
9172     return true;
9173 
9174   // Gathering cost would be too much for tiny trees.
9175   if (VectorizableTree[0]->State == TreeEntry::NeedToGather ||
9176       (VectorizableTree[1]->State == TreeEntry::NeedToGather &&
9177        VectorizableTree[0]->State != TreeEntry::ScatterVectorize &&
9178        VectorizableTree[0]->State != TreeEntry::StridedVectorize))
9179     return false;
9180 
9181   return true;
9182 }
9183 
9184 static bool isLoadCombineCandidateImpl(Value *Root, unsigned NumElts,
9185                                        TargetTransformInfo *TTI,
9186                                        bool MustMatchOrInst) {
9187   // Look past the root to find a source value. Arbitrarily follow the
9188   // path through operand 0 of any 'or'. Also, peek through optional
9189   // shift-left-by-multiple-of-8-bits.
9190   Value *ZextLoad = Root;
9191   const APInt *ShAmtC;
9192   bool FoundOr = false;
9193   while (!isa<ConstantExpr>(ZextLoad) &&
9194          (match(ZextLoad, m_Or(m_Value(), m_Value())) ||
9195           (match(ZextLoad, m_Shl(m_Value(), m_APInt(ShAmtC))) &&
9196            ShAmtC->urem(8) == 0))) {
9197     auto *BinOp = cast<BinaryOperator>(ZextLoad);
9198     ZextLoad = BinOp->getOperand(0);
9199     if (BinOp->getOpcode() == Instruction::Or)
9200       FoundOr = true;
9201   }
9202   // Check if the input is an extended load of the required or/shift expression.
9203   Value *Load;
9204   if ((MustMatchOrInst && !FoundOr) || ZextLoad == Root ||
9205       !match(ZextLoad, m_ZExt(m_Value(Load))) || !isa<LoadInst>(Load))
9206     return false;
9207 
9208   // Require that the total load bit width is a legal integer type.
9209   // For example, <8 x i8> --> i64 is a legal integer on a 64-bit target.
9210   // But <16 x i8> --> i128 is not, so the backend probably can't reduce it.
9211   Type *SrcTy = Load->getType();
9212   unsigned LoadBitWidth = SrcTy->getIntegerBitWidth() * NumElts;
9213   if (!TTI->isTypeLegal(IntegerType::get(Root->getContext(), LoadBitWidth)))
9214     return false;
9215 
9216   // Everything matched - assume that we can fold the whole sequence using
9217   // load combining.
9218   LLVM_DEBUG(dbgs() << "SLP: Assume load combining for tree starting at "
9219              << *(cast<Instruction>(Root)) << "\n");
9220 
9221   return true;
9222 }
9223 
9224 bool BoUpSLP::isLoadCombineReductionCandidate(RecurKind RdxKind) const {
9225   if (RdxKind != RecurKind::Or)
9226     return false;
9227 
9228   unsigned NumElts = VectorizableTree[0]->Scalars.size();
9229   Value *FirstReduced = VectorizableTree[0]->Scalars[0];
9230   return isLoadCombineCandidateImpl(FirstReduced, NumElts, TTI,
9231                                     /* MatchOr */ false);
9232 }
9233 
9234 bool BoUpSLP::isLoadCombineCandidate() const {
9235   // Peek through a final sequence of stores and check if all operations are
9236   // likely to be load-combined.
9237   unsigned NumElts = VectorizableTree[0]->Scalars.size();
9238   for (Value *Scalar : VectorizableTree[0]->Scalars) {
9239     Value *X;
9240     if (!match(Scalar, m_Store(m_Value(X), m_Value())) ||
9241         !isLoadCombineCandidateImpl(X, NumElts, TTI, /* MatchOr */ true))
9242       return false;
9243   }
9244   return true;
9245 }
9246 
9247 bool BoUpSLP::isTreeTinyAndNotFullyVectorizable(bool ForReduction) const {
9248   // No need to vectorize inserts of gathered values.
9249   if (VectorizableTree.size() == 2 &&
9250       isa<InsertElementInst>(VectorizableTree[0]->Scalars[0]) &&
9251       VectorizableTree[1]->State == TreeEntry::NeedToGather &&
9252       (VectorizableTree[1]->getVectorFactor() <= 2 ||
9253        !(isSplat(VectorizableTree[1]->Scalars) ||
9254          allConstant(VectorizableTree[1]->Scalars))))
9255     return true;
9256 
9257   // If the graph includes only PHI nodes and gathers, it is defnitely not
9258   // profitable for the vectorization, we can skip it, if the cost threshold is
9259   // default. The cost of vectorized PHI nodes is almost always 0 + the cost of
9260   // gathers/buildvectors.
9261   constexpr int Limit = 4;
9262   if (!ForReduction && !SLPCostThreshold.getNumOccurrences() &&
9263       !VectorizableTree.empty() &&
9264       all_of(VectorizableTree, [&](const std::unique_ptr<TreeEntry> &TE) {
9265         return (TE->State == TreeEntry::NeedToGather &&
9266                 TE->getOpcode() != Instruction::ExtractElement &&
9267                 count_if(TE->Scalars, IsaPred<ExtractElementInst>) <= Limit) ||
9268                TE->getOpcode() == Instruction::PHI;
9269       }))
9270     return true;
9271 
9272   // We can vectorize the tree if its size is greater than or equal to the
9273   // minimum size specified by the MinTreeSize command line option.
9274   if (VectorizableTree.size() >= MinTreeSize)
9275     return false;
9276 
9277   // If we have a tiny tree (a tree whose size is less than MinTreeSize), we
9278   // can vectorize it if we can prove it fully vectorizable.
9279   if (isFullyVectorizableTinyTree(ForReduction))
9280     return false;
9281 
9282   // Check if any of the gather node forms an insertelement buildvector
9283   // somewhere.
9284   bool IsAllowedSingleBVNode =
9285       VectorizableTree.size() > 1 ||
9286       (VectorizableTree.size() == 1 && VectorizableTree.front()->getOpcode() &&
9287        VectorizableTree.front()->getOpcode() != Instruction::PHI &&
9288        VectorizableTree.front()->getOpcode() != Instruction::GetElementPtr &&
9289        allSameBlock(VectorizableTree.front()->Scalars));
9290   if (any_of(VectorizableTree, [&](const std::unique_ptr<TreeEntry> &TE) {
9291         return TE->State == TreeEntry::NeedToGather &&
9292                all_of(TE->Scalars, [&](Value *V) {
9293                  return isa<ExtractElementInst, UndefValue>(V) ||
9294                         (IsAllowedSingleBVNode &&
9295                          !V->hasNUsesOrMore(UsesLimit) &&
9296                          any_of(V->users(), IsaPred<InsertElementInst>));
9297                });
9298       }))
9299     return false;
9300 
9301   assert(VectorizableTree.empty()
9302              ? ExternalUses.empty()
9303              : true && "We shouldn't have any external users");
9304 
9305   // Otherwise, we can't vectorize the tree. It is both tiny and not fully
9306   // vectorizable.
9307   return true;
9308 }
